mapper.select:
/* SmsBadwordMapper.getBadwordManageList */ SELECT BADWORD_ID, KEYWORD, KEYWORD_NORMALIZED, CATEGORY, MATCH_TYPE, SEVERITY, SOURCE, USE_YN
FROM TB_CM_SMS_BADWORD WHERE 1=1
AND KEYWORD LIKE '%' || #{keyword} || '%'
AND CATEGORY = #{category}
AND MATCH_TYPE = #{matchType}
AND SEVERITY = #{severity}
AND USE_YN = #{useYn}
ORDER BY BADWORD_ID

mapper.delete:
/* SmsBadwordMapper.deleteBadwordManage */
DELETE FROM TB_CM_SMS_BADWORD
WHERE   BADWORD_ID = #{badwordId}

mapper.select:
/* SmsBadwordMapper.getMsgBlockLogList */
SELECT L.MSG_BLOCK_ID, L.BLOCK_TYPE, L.BADWORD_ID, B.KEYWORD, L.URL_CHECK_ID, C.URL, C.URL_CHECK_SOURCE, C.REQUEST_METHOD, C.REQUEST, C.RESPONSE, C.REQUEST_DT, C.RESPONSE_DT, C.STATUS_CODE, L.MSG_STATUS, L.MSG_CONTENT, SBPENC.D(L.CALLBACK) AS CALLBACK, L.S_OGN_CD, L.S_OGN_FG, L.S_USER_ID, TO_CHAR(TO_DATE(L.REG_DT, 'yyyymmddhh24miss'), 'yyyy-mm-dd hh24:mi:ss') AS REG_DT
FROM TB_CM_SMS_MESSAGE_BLOCK L LEFT OUTER JOIN TB_CM_SMS_BADWORD B ON B.BADWORD_ID = L.BADWORD_ID LEFT OUTER JOIN TB_CM_SMS_MESSAGE_BLOCK_API C ON C.URL_CHECK_ID = L.URL_CHECK_ID WHERE 1=1
AND TO_DATE(L.REG_DT, 'YYYYMMDDHH24MISS') >= TO_DATE(#{startDate}, 'YYYYMMDD')
AND TO_DATE(L.REG_DT, 'YYYYMMDDHH24MISS') < TO_DATE(#{endDate}, 'YYYYMMDD') + 1
AND L.BLOCK_TYPE = #{blockType}
AND B.KEYWORD LIKE '%' || #{triggeredKeyword} || '%'
AND C.URL LIKE '%' || #{triggeredUrl} || '%'
AND L.MSG_STATUS = #{msgStatus}
ORDER BY L.REG_DT DESC
